import React, { useRef, useState } from 'react';
import { AppBar, Toolbar, Typography, Button, Snackbar, Alert } from '@mui/material';
import fetchModel from '../../lib/fetchModelData';

const TopBar = ({ context, currentUser, onLogout, onPhotoUploaded }) => {
  const fileInputRef = useRef(null);
  const [uploading, setUploading] = useState(false);
  const [snackbar, setSnackbar] = useState({ open: false, message: '', severity: 'success' });

  // Khi nhấn nút "Add Photo" → mở hộp thoại chọn file
  const handleAddPhotoClick = () => {
    fileInputRef.current.click();
  };

  // Khi user chọn file → upload lên server
  const handleFileChange = async (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    setUploading(true);

    try {
      // Tạo FormData để gửi file
      const formData = new FormData();
      formData.append("photo", selectedFile);

      // Gọi API upload — POST /photos/new
      const response = await fetchModel('/photos/new', 'POST', formData);

      // Thông báo thành công
      setSnackbar({
        open: true,
        message: '✅ Upload ảnh thành công!',
        severity: 'success',
      });

      // Gọi callback để App.js chuyển trang đến ảnh của user
      if (onPhotoUploaded) {
        onPhotoUploaded();
      }
    } catch (err) {
      setSnackbar({
        open: true,
        message: `❌ ${err.message || 'Upload ảnh thất bại'}`,
        severity: 'error',
      });
    } finally {
      setUploading(false);
      // Reset input file để có thể chọn lại cùng file
      e.target.value = '';
    }
  };

  const handleCloseSnackbar = () => {
    setSnackbar((prev) => ({ ...prev, open: false }));
  };

  return (
    <>
      <AppBar className="cs142-topbar-appBar" position="static">
        <Toolbar style={{ display: 'flex', justifyContent: 'space-between' }}>
          <Typography variant="h5" color="inherit">
            Phi Thiện Anh
          </Typography>

          <Typography variant="h5" color="inherit">
            {context}
          </Typography>

          {/* Hiển thị các nút khi đã đăng nhập */}
          {currentUser && (
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <Typography variant="body1" color="inherit" sx={{ fontWeight: 500 }}>
                Hi {currentUser.first_name || currentUser.login_name}
              </Typography>

              {/* Nút Add Photo */}
              <Button
                variant="contained"
                color="secondary"
                size="small"
                onClick={handleAddPhotoClick}
                disabled={uploading}
                sx={{
                  textTransform: 'none',
                  borderRadius: '8px',
                  fontWeight: 600,
                }}
              >
                {uploading ? 'Đang upload...' : 'Add Photo'}
              </Button>

              {/* Input file ẩn */}
              <input
                type="file"
                accept="image/*"
                ref={fileInputRef}
                onChange={handleFileChange}
                style={{ display: 'none' }}
              />

              {/* Nút Đăng xuất */}
              <Button
                variant="outlined"
                color="inherit"
                size="small"
                onClick={onLogout}
                sx={{
                  textTransform: 'none',
                  borderRadius: '8px',
                  fontWeight: 600,
                }}
              >
                Đăng xuất
              </Button>
            </div>
          )}
        </Toolbar>
      </AppBar>

      {/* Snackbar thông báo kết quả upload */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={4000}
        onClose={handleCloseSnackbar}
        anchorOrigin={{ vertical: 'top', horizontal: 'center' }}
      >
        <Alert onClose={handleCloseSnackbar} severity={snackbar.severity} sx={{ width: '100%' }}>
          {snackbar.message}
        </Alert>
      </Snackbar>
    </>
  );
};

export default TopBar;
